// ---- Pillar 2: Content Director — Orchestrator ----
// One webhook to trigger the full content pipeline:
//   keyword → article → social posts → featured image (parallel) → newsletter section
//   All calls are internal n8n webhooks on the same VPS (localhost:5678)
// Designed for sequential execution with partial success — failure of one step
//   does NOT block the others. Returns full summary of what completed.
//
// Architecture decisions:
//   - Internal calls via localhost (no internet round-trip, no rate limits)
//   - Article must complete first (social + image depend on it)
//   - Social + image are parallel (independent)
//   - Each sub-workflow handles its own Supabase writes and LLM fallbacks
const ENV = (typeof $env !== 'undefined' && $env) ? $env : process.env;
const b = $json.body || $json;

const keyword  = String(b.keyword  || '').trim();
const pillar   = String(b.pillar   || 'gtm').trim();
const wordTarget = parseInt(b.word_count || 1500);
if (!keyword) return [{ json: { ok: false, error: 'keyword is required' } }];

const N8N_BASE = 'http://localhost:5678/webhook';
const started = new Date().toISOString();

async function callWorkflow(path, body) {
  return this.helpers.httpRequest({
    method: 'POST', url: `${N8N_BASE}/${path}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body), json: true, timeout: 120000
  });
}

// Step 1: Write article (required first)
let article = null, articleError = null;
try {
  article = await callWorkflow.call(this, 'content/write-article', { keyword, pillar, word_count: wordTarget });
} catch (e) { articleError = e.message.slice(0, 200); }

if (!article?.ok) {
  return [{ json: { ok: false, keyword, step: 'article', error: articleError || article?.error } }];
}

// Step 2: Social posts + image in parallel (both depend on article content)
const [socialResult, imageResult] = await Promise.allSettled([
  callWorkflow.call(this, 'content/social-posts', { keyword, title: article.title, article: article.article_draft }),
  callWorkflow.call(this, 'content/generate-image', { keyword, title: article.title, style: 'featured' })
]);

const social = socialResult.status === 'fulfilled' ? socialResult.value : { ok: false, error: socialResult.reason?.message };
const image  = imageResult.status  === 'fulfilled' ? imageResult.value  : { ok: false, error: imageResult.reason?.message };

// Step 3: Newsletter section (short, from article summary — Groq 8b)
let newsletter = null;
try {
  const nRes = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: { Authorization: `Bearer ${ENV.GROQ_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'llama-3.1-8b-instant',
      messages: [
        { role: 'system', content: 'You are a newsletter writer for Markexis. Write a 100-word newsletter section (1 paragraph) summarising this article in a way that drives clicks. No fluff. End with a link placeholder: [Read the full article →]' },
        { role: 'user', content: `Article: "${article.title}"\n\nKeyword: ${keyword}\n\nArticle excerpt: ${(article.article_draft || '').replace(/<[^>]+>/g,' ').slice(0,1000)}` }
      ],
      temperature: 0.5, max_tokens: 200
    }),
    json: true, timeout: 30000
  });
  newsletter = nRes.choices[0].message.content;
} catch { newsletter = null; }

// Update Supabase with newsletter section
if (newsletter && ENV.SUPABASE_URL) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${ENV.SUPABASE_URL}/rest/v1/content_pipeline?on_conflict=keyword`,
    headers: {
      apikey: ENV.SUPABASE_ANON_KEY, Authorization: `Bearer ${ENV.SUPABASE_ANON_KEY}`,
      'Content-Type': 'application/json', Prefer: 'resolution=merge-duplicates'
    },
    body: JSON.stringify({ keyword, newsletter_section: newsletter, status: 'review', updated_at: new Date().toISOString() }),
    json: false, timeout: 15000
  }).catch(() => null);
}

const done = new Date().toISOString();
const elapsed = Math.round((new Date(done) - new Date(started)) / 1000);

return [{ json: {
  ok: true, keyword, pillar,
  summary: {
    article:   { ok: article.ok,  title: article.title, words: article.word_count },
    social:    { ok: social.ok,   linkedin: !!social.linkedin_post, tweets: social.twitter_thread?.length || 0 },
    image:     { ok: image.ok,    provider: image.provider_used, size_kb: image.size_kb },
    newsletter: { ok: !!newsletter, chars: newsletter?.length || 0 }
  },
  elapsed_seconds: elapsed,
  started, done
} }];
